const tz = 'Australia/Sydney';
const now = new Date();

// now() and (now - 24h), both as ISO with correct Sydney offset
function zonedOffsetAt(date) {
  const dtf = new Intl.DateTimeFormat('en-US', { timeZone: tz, timeZoneName: 'shortOffset' });
  const parts = dtf.formatToParts(date);
  const tzName = (parts.find(p => p.type === 'timeZoneName') || {}).value || 'GMT+10';
  const m = tzName.match(/GMT([+-])(\d{1,2})(?::?(\d{2}))?/);
  const sign = m ? m[1] : '+';
  const hh = m ? String(parseInt(m[2], 10)).padStart(2, '0') : '10';
  const mm = m && m[3] ? m[3] : '00';
  return `${sign}${hh}:${mm}`;
}

function toZonedIso(date) {
  const off = zonedOffsetAt(date);
  // Represent the instant in Sydney local time with explicit offset
  const sign = off.startsWith('-') ? -1 : 1;
  const [hh, mm] = off.slice(1).split(':').map(Number);
  const shifted = new Date(date.getTime() + sign * (hh * 60 + mm) * 60 * 1000);
  const y = shifted.getUTCFullYear();
  const mo = String(shifted.getUTCMonth() + 1).padStart(2, '0');
  const d = String(shifted.getUTCDate()).padStart(2, '0');
  const h = String(shifted.getUTCHours()).padStart(2, '0');
  const mi = String(shifted.getUTCMinutes()).padStart(2, '0');
  const s = String(shifted.getUTCSeconds()).padStart(2, '0');
  return `${y}-${mo}-${d}T${h}:${mi}:${s}${off}`;
}

const end = now;
const start = new Date(now.getTime() - 24 * 60 * 60 * 1000);
const startIso = toZonedIso(start);
const endIso = toZonedIso(end);
const runDate = toZonedIso(now).slice(0, 10);

return [{ json: { startIso, endIso, runDate, runAtIso: now.toISOString() } }];

const logs = $('Read errors and warns 24h').all().map(i => i && i.json).filter(x => x && x.id && x.agent_name);
const tasks = $('Read broken tasks 24h').all().map(i => i && i.json).filter(x => x && x.id && x.agent_name);
const runAtIso = $('Compute Date Range').first().json.runAtIso;
const runDate = $('Compute Date Range').first().json.runDate;

let errors_24h = 0, warnings_24h = 0;
const errorsByAgent = {};
const escalations = [];
for (const l of logs) {
  const lv = (l.level || '').toLowerCase();
  if (lv === 'error' || lv === 'fatal') {
    errors_24h++;
    errorsByAgent[l.agent_name] = (errorsByAgent[l.agent_name] || 0) + 1;
  } else if (lv === 'warn') {
    warnings_24h++;
  }
  const tier = l.metadata && (l.metadata.tier ?? l.metadata.escalation_tier);
  if (tier === 'T4' || tier === 4 || tier === 'T5' || tier === 5) {
    escalations.push({
      agent: l.agent_name,
      tier: tier,
      message: (l.message || '').slice(0, 240),
      created_at: l.created_at,
    });
  }
}

let failed_tasks_24h = 0, blocked_tasks_24h = 0;
const nowMs = new Date(runAtIso).getTime();
const SIX_HOURS = 6 * 60 * 60 * 1000;
const aging_blocked = [];
for (const t of tasks) {
  if (t.status === 'failed') failed_tasks_24h++;
  else if (t.status === 'blocked') {
    blocked_tasks_24h++;
    const since = new Date(t.started_at || t.created_at || 0).getTime();
    if (since > 0 && (nowMs - since) > SIX_HOURS) {
      aging_blocked.push({ id: t.id, agent: t.agent_name, task_type: t.task_type, hours_blocked: Math.round((nowMs - since) / 3600000) });
    }
  }
}

const top_agents_by_errors = Object.entries(errorsByAgent)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([agent, count]) => ({ agent, count }));

const snapshot = {
  runDate,
  errors_24h,
  warnings_24h,
  failed_tasks_24h,
  blocked_tasks_24h,
  top_agents_by_errors,
  aging_blocked,
  escalations,
};

const bypass_claude = errors_24h === 0 && warnings_24h === 0 && failed_tasks_24h === 0 && blocked_tasks_24h === 0;

if (bypass_claude) {
  return [{ json: { bypass_claude: true, snapshot, runAtIso } }];
}

const system = [
  "You are Agent #02 CTO for invest.com.au. You run once a day and produce a tight operational digest.",
  "Phase 2 deployment — same input constraints as the Master Overseer: you have agent_logs + agent_tasks, nothing more.",
  "Your job on this run is to classify severity, flag escalating issues, and suggest at most 3 follow-up actions.",
  "Do NOT invent numbers the snapshot does not support. Do NOT propose code changes in this digest — PR drafting is a separate workflow.",
  "",
  "Return a JSON block (```json ... ```) with keys: severity (one of: info|warn|error), headline (<=120 chars), recommendations (array of <=3 strings, each <=160 chars), echo {errors_24h, warnings_24h, failed_tasks_24h, blocked_tasks_24h, aging_blocked_count: N}. Follow the JSON block with a one-line plain-English digest."
].join('\n');

const user = [
  `Run at: ${runAtIso} (Sydney-local digest window: last 24h)`,
  '',
  'Snapshot (ground truth, computed deterministically):',
  '```json',
  JSON.stringify(snapshot, null, 2),
  '```',
  '',
  'Recent error/fatal/warn logs (most recent first, up to 20):',
  '```json',
  JSON.stringify(logs.slice(0, 20).map(l => ({ agent: l.agent_name, level: l.level, message: (l.message || '').slice(0, 400), created_at: l.created_at })), null, 2),
  '```',
  '',
  'Broken tasks (failed+blocked, most recent first, up to 20):',
  '```json',
  JSON.stringify(tasks.slice(0, 20).map(t => ({ id: t.id, agent: t.agent_name, task_type: t.task_type, status: t.status, priority: t.priority, updated_at: t.updated_at })), null, 2),
  '```',
].join('\n');

return [{ json: { bypass_claude: false, snapshot, system, user, runAtIso } }];

const resp = $('Call Claude').first().json || {};
const snapshot = $('Build CTO prompt').first().json.snapshot;
const runAtIso = $('Build CTO prompt').first().json.runAtIso;

// Extract the assistant text block(s)
const textBlocks = Array.isArray(resp.content) ? resp.content.filter(c => c && c.type === 'text').map(c => c.text || '') : [];
const combined = textBlocks.join('\n');

// Try to find a JSON block of the form ```json ... ``` or the first {...} object
let parsed = null;
const fenceMatch = combined.match(/```json\s*([\s\S]*?)```/i);
if (fenceMatch) {
  try { parsed = JSON.parse(fenceMatch[1].trim()); } catch (e) { parsed = null; }
}
if (!parsed) {
  const braceMatch = combined.match(/\{[\s\S]*\}/);
  if (braceMatch) {
    try { parsed = JSON.parse(braceMatch[0]); } catch (e) { parsed = null; }
  }
}

// Derive level from snapshot (not from Claude — Claude's severity is advisory)
let level = 'info';
if (snapshot.warnings_24h > 0 || snapshot.blocked_tasks_24h > 0) level = 'warn';
if (snapshot.errors_24h > 0 || snapshot.failed_tasks_24h > 0 || snapshot.escalations.length > 0) level = 'error';

const headline = (parsed && typeof parsed.headline === 'string') ? parsed.headline.slice(0, 240) : 'CTO daily digest';
const recommendations = (parsed && Array.isArray(parsed.recommendations)) ? parsed.recommendations.slice(0, 3).map(s => String(s).slice(0, 240)) : [];

return [{
  json: {
    agent_name: 'cto',
    level,
    message: headline,
    metadata: {
      daily_digest: true,
      snapshot,
      claude: {
        severity: parsed && parsed.severity,
        headline,
        recommendations,
        raw_text: combined.slice(0, 4000),
        model: resp.model || 'claude-opus-4-7',
        stop_reason: resp.stop_reason,
        usage: resp.usage,
      },
      run_at: runAtIso,
    },
  },
}];
